import{_ as a,o as e,c as t,j as r,a as b,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"必杀技","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/武技类/必杀技.md","filePath":"4.资源分区/6.技艺及称号/武技类/必杀技.md"}'),s={name:"4.资源分区/6.技艺及称号/武技类/必杀技.md"};function o(d,p,l,_,i,c){return e(),t("div",null,[...p[0]||(p[0]=[r("h1",{id:"必杀技",tabindex:"-1"},[b("必杀技 "),r("a",{class:"header-anchor",href:"#必杀技","aria-label":'Permalink to "必杀技"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌039")])])],-1),n('<h1 id="必杀技-1" tabindex="-1">必杀技 <a class="header-anchor" href="#必杀技-1" aria-label="Permalink to &quot;必杀技&quot;">​</a></h1><p>必杀技<br> 原典：忍者杀手<br> 描述：满足特定条件下，可以使出具有强大威力的招式。虽然在战斗中相当不稳定，然而只要能够击发，就意味着可以在战局中取得相当的优势。</p><p>注1：若无特殊说明，则必杀技效果中提到的替换不会真正的占用招式，可以正常结合招式使用，但多个必杀技无法同时在一次攻击中生效。</p><p>注2：若无特殊说明，则必杀技无法与毁灭/湮灭同时生效。</p><p>注3：必杀技下属的能力可以按照自由顺序购买。</p><p>必杀技：崩拳<br> 价格：C+1500<br> 描述：向前踏进并挥出的猛烈中段攻击能够贯穿躯干、粉碎岩石。<br> 效果：<br> 当投掷一次你的攻击检定时，不计算任何能力提升，且出数大于或等于总数的一半（不包含附加成功带来的数值），你可以将那次攻击替换为「必杀技：崩拳」</p><p>必杀技：崩拳：本次攻击加骰提升1级处理（上限8加骰），并额外进行一次DP等同【力量】的特殊检定，并将传奇力量数值计入出目，随后本次攻击获得等同特殊检定出目*1点【破甲】，若这些破甲在处理目标防御后仍有剩余，则你可以将该能力提供的剩余破甲转化为等量攻击检定上的增强加值。</p><p>此外，这次攻击具有【贯穿】特性，在命中后还会使目标以绊摔或击退规则对抗伤害出目（由你自选），失败则其立刻进入伏地状态并被击退差值/米。</p><p>上述提及的特殊检定无法计入任何额外加值，也无法因任何原因调整最终出目。</p><p>必杀技：倒挂回旋踢<br> 价格：C+1000<br> 描述：传说中的反击空手道技。在压低身体回避敌人攻击的同时，空翻跳跃上踢对手的下颚并折断脖子。<br> 效果：「倒挂回旋踢」是一种特殊的反击能力，因此会正常视为主动招式处理；你需要先在自己的回合内保留一个移动动作，并在本轮内自身的回合外受到一次攻击时才能使用这一能力。</p><p>你需要先使用反射动作调用保留的移动动作，对攻击你的（单一目标）进行一次招架行为，此次招架需要使用【武技】技能计算招架抵消出目，视为移出范围处理，招架发生时，若这次攻击不对你造成任何伤害或者是异常点数且对手处于你的触及范围内，则你可以将这次招架行为替换为「必杀技：倒挂回旋踢」。</p><p>必杀技：倒挂回旋踢：本次招架将会同时视为一次反击，因此在招架的基础上还会对攻击你的那一单位造成等同【招架的伤害抵消数】的物理钝击伤害（这些伤害只能被伤害减免，吸收类效果抵消）。</p><p>必杀技：月影<br> 价格：C+2000<br> 描述：居合道的奥义。快速近身并挥出大范围的横扫斩击，出现在敌人身后的同时将其一刀两断。<br> 效果：<br> 当投掷一次你的攻击检定时，不计算任何能力提升，且出数大于或等于总数的一半（不包含附加成功带来的数值），你可以支付2点意志力，将那次攻击替换为「必杀技：月影」。</p><p>必杀技：月影：你可以在触发该能力后，先进行一次距离不超过等同你【敏捷】*3米的固定移动，随后再进行上述投掷攻击检定的攻击，本次攻击将转变为对触及距离内的所有敌对目标进行攻击，附带B级措手不及的效果。</p><p>必杀技：大蛇正<br> 价格：B+2000<br> 描述：用鞭子对远距离的敌人发动风暴般的鞭子猛攻后，缠住他们的腿与手腕。紧接着，用力拉鞭所产生的旋转和摩擦的势头，使鞭子的刀刃像电锯一样旋转，残暴地摧毁敌人的四肢与身体。<br> 效果：<br> 当投掷一次你的攻击检定时，不计算任何能力提升，且出数大于或等于总数的一半（不包含附加成功带来的数值），你可以将那次攻击替换为「必杀技：大蛇正」。</p><p>必杀技：大蛇正：本次攻击附带等同【力量/4】点二档肢体妨碍不良点数，并具有【幻灭】特性；在攻击命中后，目标还需要使用反射或强韧豁免（目标自选）对抗这次攻击的成功数，失败则其陷入【伏地】状态，并被你向任意一个指定方向拖拽差值*1米的距离。</p><p>必杀技：破门枪<br> 价格：B+2000<br> 描述：基于以枪术名手闻名的大和忍者传说的可怕杀人技。在Tackle的同时，用长枪刺穿敌人的躯干，在保持巨大力量的同时进行空手道突进，将敌人猛击到身后的墙壁上。集中一点的空手道的穿透力极度惊人，大枪的尖端带有空手道红热或Aura，甚至穿透铠甲和敌人的肉体刺入墙壁。<br> 效果：<br> 当投掷一次你的攻击检定时，不计算任何能力提升，且出数大于或等于总数的一半（不包含附加成功带来的数值），你可以将那次攻击替换为「必杀技：破门枪」</p><p>必杀技：破门枪：本次攻击具有【接触攻击】与【贯穿】特性，目标在被命中后，必须使用反射豁免对抗伤害出目，失败则其陷入B级创伤来源的【定身】状态，持续一轮，并被【弹飞】。</p><p>【弹飞】：目标被弹飞等同上述攻击成功数*1米，这是一个类冲撞效果，因此针对冲撞/击退的效果会正常生效（你无法将目标向上方弹飞）。<br> 需要注意的是，定身下的目标无法对该能力进行的弹飞进行豁免对抗，因此该能力也无需进行豁免，一旦目标免疫定身效果，则该弹飞效果无法生效。</p><p>变体：镇痛剂<br> 描述：这个忍者高高跃起，尽全力用剑下劈敌人的脖子或头部。这沉重的一击将full面甲或者铠甲摧毁，将敌人介错。敌人将再也感觉不到痛苦。<br> 效果：镇痛剂是破门枪的变体，因此触发要求，效果与价格皆等同于破门枪，但不具有【弹飞】效果，也不会使目标【定身】。镇痛剂不具有【接触攻击】效果，但可以无视盔甲防御（这是一个B级创伤来源的效果），并具有【幻灭】，同时目标被命中后需要使用强韧豁免对抗伤害出目，失败则陷入【伏地】状态。</p><p>必杀技：死针<br> 价格：A+4000<br> 描述：禁断的黑暗空手道奥义，将手指插入敌人的要害穴位，使敌人立刻爆发四散。即使没有立刻爆发四散，也会承受绝大的伤害。<br> 效果：当投掷一次你的攻击检定时，不计算任何能力提升，且出数大于或等于总数的一半（不包含附加成功带来的数值），你可以将那次攻击替换为「必杀技：死针」。</p><p>必杀技：死针：本次攻击出目将在原本的基础上增加一半，并在命中后使目标采用强韧豁免对抗伤害出目，失败则目标立刻死亡，这是一个A级创伤来源的【即死】效果。若目标免疫上述即死效果的影响，无论是因何效果免疫或在承受效果后依然存活，则这次攻击视为具有【幻灭】特性。</p><p>特殊的是，使用「必杀技：死针」需要插入目标的死穴，因此你会在这次攻击时如同进行了一次部位攻击，部位减值4，当目标因任何效果免疫了部位攻击时，「必杀技：死针」的效果也将无法生效。</p><p>必杀技：强手里剑<br> 价格：B+2000<br> 描述：灌注了全身空手道的手里剑投掷的破坏力可以和轨道步枪匹敌，在火花四溅中击毁盔甲、击飞敌人。<br> 效果：<br> 购买后，你获得【射击风格：强手里剑（单发）】。</p><p>射击风格：强手里剑（单发）<br> 效果：你的投掷攻击附带等同【力量】一半的【熔毁】，并在命中后使目标以强韧豁免对抗伤害出目，失败则其被【弹飞】。</p><p>【弹飞】：目标被弹飞等同上述攻击成功数*1米，这是一个类冲撞效果，因此针对冲撞/击退的效果会正常生效（你无法将目标向上方弹飞）。</p><p>此外，当你以投掷类别的攻击时，若你的攻击检定在不计算任何能力提升时，出数大于或等于总数的一半（不包含附加成功带来的数值），射击风格：强手里剑（单发）的效果将会被替换为「必杀技：强手里剑」。</p><p>必杀技：强手里剑：本次投掷攻击附带等同【力量】属性*1点【熔毁】，具有【幻灭】特性。</p><p>必杀技：串挂<br> 价格：B+4000<br> 描述：这是大和忍者擅长的无慈悲射击。弓矢的强烈一击会将敌人击飞，直接刺穿在墙壁或树干上。再将无防备的敌人沐浴在追击的箭雨中。<br> 效果：<br> 当投掷一次你的攻击检定时，不计算任何能力提升，且出数大于或等于总数的一半（不包含附加成功带来的数值），你可以将那次攻击替换为「必杀技：串挂」。</p><p>必杀技：串挂：本次攻击命中后，目标需要进行一次反射豁免，失败则陷入持续一轮的定身效果（视为B级创伤来源）并被【弹飞】；这还会视为额外进行了等同【敏捷/4】次攻击，这些额外次数的攻击每次只会造成1点伤害与1点多次攻击减值，但只需与上述造成定身的攻击同时处理一次伤害减免类效果即可。</p><p>【弹飞】：目标被弹飞等同上述攻击成功数*1米，这是一个类冲撞效果，因此针对冲撞/击退的效果会正常生效（你无法将目标向上方弹飞）。<br> 需要注意的是，定身下的目标无法对该能力进行的弹飞进行豁免对抗，因此该能力也无需进行豁免，一旦目标免疫定身效果，则该弹飞效果无法生效。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',33)])])}const m=a(s,[["render",o]]);export{f as __pageData,m as default};
